{
  "AWSTemplateFormatVersion": "2010-09-09",
  "Description": "Create IAM role, instance profile, and EC2 instance for MWAA runner",
  "Parameters": {
    "VpcId": {
      "Type": "AWS::EC2::VPC::Id",
      "Description": "VPC ID for the security group"
    },
    "SubnetId": {
      "Type": "String",
      "Description": "Subnet ID for the EC2 instance"
    },
    "S3BucketName": {
      "Type": "String",
      "Description": "Name of the S3 bucket for write access"
    },
    "ExecutionId": {
      "Type": "String",
      "Description": "Unique execution ID for resource naming",
      "Default": "default"
    },
    "AmiId": {"Type": "AWS::EC2::Image::Id", "Description": "Latest AMI for Amazon Linux 2023"}
  },
  "Resources": {
    "MWAAInstanceRole": {
      "Type": "AWS::IAM::Role",
      "Properties": {
        "RoleName": {
          "Fn::Sub": "mwaa-instance-role-${ExecutionId}"
        },
        "AssumeRolePolicyDocument": {
          "Version": "2012-10-17",
          "Statement": [
            {
              "Effect": "Allow",
              "Principal": {
                "Service": "ec2.amazonaws.com"
              },
              "Action": "sts:AssumeRole"
            }
          ]
        },
        "ManagedPolicyArns": [
          { "Fn::Sub": "arn:${AWS::Partition}:iam::aws:policy/AmazonSSMManagedInstanceCore" }
        ],
        "Policies": [
          {
            "PolicyName": "S3AccessPolicy",
            "PolicyDocument": {
              "Version": "2012-10-17",
              "Statement": [
                {
                  "Sid": "ListBucket",
                  "Effect": "Allow",
                  "Action": "s3:ListBucket",
                  "Resource": [
                    {
                      "Fn::Sub": "arn:${AWS::Partition}:s3:::${S3BucketName}"
                    }
                  ]
                },
                {
                  "Sid": "ReadWriteObjectActions",
                  "Effect": "Allow",
                  "Action": ["s3:GetObject", "s3:PutObject"],
                  "Resource": {
                    "Fn::Sub": "arn:${AWS::Partition}:s3:::${S3BucketName}/*"
                  }
                }
              ]
            }
          }
        ]
      }
    },
    "MWAAInstanceProfile": {
      "Type": "AWS::IAM::InstanceProfile",
      "Properties": {
        "InstanceProfileName": {
          "Fn::Sub": "mwaa-instance-profile-${ExecutionId}"
        },
        "Roles": [
          {
            "Ref": "MWAAInstanceRole"
          }
        ]
      }
    },
    "MWAASecurityGroup": {
      "Type": "AWS::EC2::SecurityGroup",
      "Properties": {
        "GroupDescription": "Security group for MWAA runner instance - allows HTTPS outbound",
        "GroupName": {
          "Fn::Sub": "mwaa-runner-sg-${ExecutionId}"
        },
        "VpcId": {
          "Ref": "VpcId"
        },
        "SecurityGroupEgress": [
          {
            "IpProtocol": "tcp",
            "FromPort": 443,
            "ToPort": 443,
            "CidrIp": "0.0.0.0/0",
            "Description": "Allow HTTPS outbound traffic"
          }
        ],
        "Tags": [
          {
            "Key": "Name",
            "Value": {
              "Fn::Sub": "mwaa-runner-sg-${ExecutionId}"
            }
          },
          {
            "Key": "CreatedBy",
            "Value": "AWSSupport-ValidateMWAADependencies"
          }
        ]
      }
    },
    "MWAARunnerInstance": {
      "Type": "AWS::EC2::Instance",
      "DependsOn": "MWAAInstanceProfile",
      "Properties": {
        "ImageId": {"Ref": "AmiId"},
        "InstanceType": "t3.large",
        "Monitoring": true,
        "NetworkInterfaces": [
          {
            "DeviceIndex": "0",
            "SubnetId": { "Ref": "SubnetId" },
            "AssociatePublicIpAddress": true,
            "GroupSet": [{ "Ref": "MWAASecurityGroup" }]
          }
        ],
        "BlockDeviceMappings": [
          {
            "DeviceName": "/dev/xvda",
            "Ebs": {
              "VolumeSize": 50,
              "VolumeType": "gp3",
              "Encrypted": true
            }
          }
        ],
        "EbsOptimized": true,
        "IamInstanceProfile": {
          "Ref": "MWAAInstanceProfile"
        },
        "UserData": {
          "Fn::Base64": "#!/bin/bash\ndnf install -y git\ndnf install -y docker\nsystemctl start docker\nsystemctl enable docker.service"
        },
        "MetadataOptions":
          {
            "HttpTokens": "required"
          },
        "Tags": [
          {
            "Key": "Name",
            "Value": {
              "Fn::Sub": "mwaa-runner-${ExecutionId}"
            }
          },
          {
            "Key": "CreatedBy",
            "Value": "AWSSupport-ValidateMWAADependencies"
          }
        ]
      }
    }
  },
  "Outputs": {
    "InstanceId": {
      "Description": "ID of the created EC2 instance",
      "Value": {
        "Ref": "MWAARunnerInstance"
      }
    }
  }
}
